@using sv_1d50f10f7991409b88dacb4ce670e5ee.Models
@namespace sv_1d50f10f7991409b88dacb4ce670e5ee.Components.Pages.Settings

<div class="settings-section">
    <h3>Profile</h3>
    <p class="text-muted">Manage your personal information</p>

    <div class="profile-avatar-area mb-4">
        <div class="avatar-preview">
            @if (!string.IsNullOrWhiteSpace(AvatarUrl))
            {
                <img src="@AvatarUrl" alt="Avatar" class="avatar-img" />
            }
            else
            {
                <div class="avatar-placeholder">No Avatar</div>
            }
        </div>
        <div class="avatar-url-display">
            <label class="form-label">Avatar URL</label>
            <input type="text" class="form-control" value="@AvatarUrl"
                   @oninput="e => AvatarUrl = e.Value?.ToString() ?? string.Empty" />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="DisplayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @bind="Bio"></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">
            Discard Changes
        </button>
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 fade-in" role="alert">
            ✅ Profile saved successfully!
        </div>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_saving)
        {
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        _showSuccess = false;
    }
}

@using sv_1d50f10f7991409b88dacb4ce670e5ee.Models
@namespace sv_1d50f10f7991409b88dacb4ce670e5ee.Components.Pages.Settings

<div class="settings-section">
    <h3>Notifications</h3>
    <p class="text-muted">Configure how you receive notifications</p>

    <div class="mb-4">
        <h5>Notification Channels</h5>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@EmailNotifications"
                   @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@PushNotifications"
                   @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@WeeklyDigest"
                   @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h5>Muted Channels</h5>
        <p class="text-muted small">Check channels you want to mute</p>
        @if (AllChannels.Count > 0)
        {
            @foreach (var channel in AllChannels)
            {
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="ch-@channel"
                           checked="@MutedChannels.Contains(channel)"
                           @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="ch-@channel">#@channel</label>
                </div>
            }
        }
        else
        {
            <p class="text-muted">No channels available.</p>
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @(_saving ? "Saving..." : "Save Preferences")
    </button>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 fade-in" role="alert">
            ✅ Notification preferences saved!
        </div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];
    private List<string> AllChannels = [];
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_saving)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            AllChannels = [.. Prefs.MutedChannels];
            MutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@using sv_1d50f10f7991409b88dacb4ce670e5ee.Models
@namespace sv_1d50f10f7991409b88dacb4ce670e5ee.Components.Pages.Settings

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage passwords, sessions, and two-factor authentication</p>

    @* Change Password Panel *@
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span>🔑 Change Password</span>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(_passwordError))
                {
                    <div class="alert alert-danger">@_passwordError</div>
                }
                @if (_passwordSuccess)
                {
                    <div class="alert alert-success fade-in">✅ Password updated successfully!</div>
                }

                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @(_changingPassword ? "Updating..." : "Update Password")
                </button>
            </div>
        }
    </div>

    @* Two-Factor Authentication *@
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@TwoFactorEnabled"
                       @onchange="e => OnToggleTwoFactor.InvokeAsync((bool)(e.Value ?? false))" />
            </div>
        </div>
    </div>

    @if (Security?.LastPasswordChange is not null)
    {
        <p class="text-muted small mb-4">
            Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    @* Active Sessions *@
    <h5>Active Sessions</h5>
    @if (Security?.Sessions is { Count: > 0 })
    {
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Security.Sessions)
                    {
                        var isCurrent = session.Id == Security.Sessions[0].Id;
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
    else
    {
        <p class="text-muted">No active sessions found.</p>
    }

    @* Revoke Confirmation Dialog *@
    @if (_sessionToRevoke is not null)
    {
        <div class="modal-backdrop show"></div>
        <div class="modal d-block" tabindex="-1">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                        <p class="text-muted small">This will immediately sign out that device.</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                            @(_revoking ? "Revoking..." : "Revoke Session")
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnToggleTwoFactor { get; set; }

    private bool TwoFactorEnabled;

    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _passwordSuccess;
    private bool _changingPassword;

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override void OnParametersSet()
    {
        if (Security is not null)
        {
            TwoFactorEnabled = Security.TwoFactorEnabled;
        }
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _changingPassword = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _changingPassword = false;
        _passwordSuccess = true;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        _revoking = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_1d50f10f7991409b88dacb4ce670e5ee.Models
@namespace sv_1d50f10f7991409b88dacb4ce670e5ee.Components.Pages.Settings

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize the look and feel of the application</p>

    @* Theme *@
    <div class="mb-4">
        <h5>Theme</h5>
        <div class="d-flex gap-3">
            @foreach (var theme in new[] { "Light", "Dark", "System" })
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                           value="@theme" checked="@(Theme == theme)"
                           @onchange="() => Theme = theme" />
                    <label class="form-check-label" for="theme-@theme">@theme</label>
                </div>
            }
        </div>
    </div>

    @* Font Size *@
    <div class="mb-4">
        <h5>Font Size</h5>
        <div class="d-flex gap-3">
            @foreach (var size in new[] { "Small", "Medium", "Large" })
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                           value="@size" checked="@(FontSize == size)"
                           @onchange="() => FontSize = size" />
                    <label class="form-check-label" for="fs-@size">@size</label>
                </div>
            }
        </div>
    </div>

    @* Language *@
    <div class="mb-4">
        <h5>Language</h5>
        <select class="form-select" style="max-width: 300px" @bind="Language">
            <option value="English">English</option>
            <option value="Spanish">Spanish</option>
            <option value="French">French</option>
            <option value="German">German</option>
            <option value="Japanese">Japanese</option>
            <option value="Chinese">Chinese</option>
        </select>
    </div>

    @* Compact Mode *@
    <div class="mb-4">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="compactMode"
                   checked="@CompactMode"
                   @onchange="e => CompactMode = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="compactMode">Compact Mode</label>
        </div>
        <small class="text-muted">Reduce spacing and padding throughout the interface</small>
    </div>

