                <p class="preview-text">This is how your content will look with the selected settings.</p>
                <div class="preview-card">
                    <span>📊 Analytics</span>
                    <span class="preview-value">1,234</span>
                </div>
                <div class="preview-card">
                    <span>👥 Users</span>
                    <span class="preview-value">567</span>
                </div>
            </div>
        </div>
