        await OnSave.InvokeAsync(updated);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@page "/settings"
@using sv_1d50f10f7991409b88dacb4ce670e5ee.Models
@using sv_1d50f10f7991409b88dacb4ce670e5ee.Services
@using sv_1d50f10f7991409b88dacb4ce670e5ee.Components.Pages.Settings
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => { _activeSection = s; }" />

    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_profile" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@_notificationPrefs" OnSave="SaveNotificationPrefsAsync" />
                    break;
                case "Security":
                    <SecuritySection Security="@_security"
                                     OnRevokeSession="RevokeSessionAsync"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnToggleTwoFactor="ToggleTwoFactorAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@_appearance" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllAsync();
        _loading = false;
    }

    private async Task LoadAllAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notificationPrefs = notifsTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task ToggleTwoFactorAsync(bool enabled)
    {
        if (_security is not null)
        {
            _security = _security with { TwoFactorEnabled = enabled };
        }
        await Task.CompletedTask;
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

/* ─── Settings Layout ─── */
.settings-layout {
    display: flex;
