@namespace sv_1d50f10f7991409b88dacb4ce670e5ee.Components.Pages.Settings

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage passwords, sessions, and two-factor authentication</p>

    @* Change Password Panel *@
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span>🔑 Change Password</span>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(_passwordError))
                {
                    <div class="alert alert-danger">@_passwordError</div>
                }
                @if (_passwordSuccess)
                {
                    <div class="alert alert-success fade-in">✅ Password updated successfully!</div>
                }

                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @(_changingPassword ? "Updating..." : "Update Password")
                </button>
            </div>
        }
    </div>

    @* Two-Factor Authentication *@
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@TwoFactorEnabled"
                       @onchange="e => OnToggleTwoFactor.InvokeAsync((bool)(e.Value ?? false))" />
            </div>
        </div>
    </div>

    @if (Security?.LastPasswordChange is not null)
    {
        <p class="text-muted small mb-4">
            Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    @* Active Sessions *@
    <h5>Active Sessions</h5>
    @if (Security?.Sessions is { Count: > 0 })
    {
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Security.Sessions)
                    {
                        var isCurrent = session.Id == Security.Sessions[0].Id;
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
    else
    {
        <p class="text-muted">No active sessions found.</p>
    }

    @* Revoke Confirmation Dialog *@
    @if (_sessionToRevoke is not null)
    {
        <div class="modal-backdrop show"></div>
        <div class="modal d-block" tabindex="-1">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                        <p class="text-muted small">This will immediately sign out that device.</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                            @(_revoking ? "Revoking..." : "Revoke Session")
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnToggleTwoFactor { get; set; }

    private bool TwoFactorEnabled;

    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _passwordSuccess;
    private bool _changingPassword;

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override void OnParametersSet()
    {
        if (Security is not null)
        {
            TwoFactorEnabled = Security.TwoFactorEnabled;
        }
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _changingPassword = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _changingPassword = false;
        _passwordSuccess = true;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        _revoking = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
