@using sv_1d50f10f7991409b88dacb4ce670e5ee.Models
@namespace sv_1d50f10f7991409b88dacb4ce670e5ee.Components.Pages.Settings

<div class="settings-section">
    <h3>Notifications</h3>
    <p class="text-muted">Configure how you receive notifications</p>

    <div class="mb-4">
        <h5>Notification Channels</h5>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@EmailNotifications"
                   @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@PushNotifications"
                   @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@WeeklyDigest"
                   @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h5>Muted Channels</h5>
        <p class="text-muted small">Check channels you want to mute</p>
        @if (AllChannels.Count > 0)
        {
            @foreach (var channel in AllChannels)
            {
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="ch-@channel"
                           checked="@MutedChannels.Contains(channel)"
