@using sv_1d50f10f7991409b88dacb4ce670e5ee.Models
@namespace sv_1d50f10f7991409b88dacb4ce670e5ee.Components.Pages.Settings

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize the look and feel of the application</p>

    @* Theme *@
    <div class="mb-4">
        <h5>Theme</h5>
        <div class="d-flex gap-3">
            @foreach (var theme in new[] { "Light", "Dark", "System" })
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                           value="@theme" checked="@(Theme == theme)"
                           @onchange="() => Theme = theme" />
                    <label class="form-check-label" for="theme-@theme">@theme</label>
                </div>
            }
        </div>
    </div>

    @* Font Size *@
    <div class="mb-4">
        <h5>Font Size</h5>
        <div class="d-flex gap-3">
            @foreach (var size in new[] { "Small", "Medium", "Large" })
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                           value="@size" checked="@(FontSize == size)"
                           @onchange="() => FontSize = size" />
                    <label class="form-check-label" for="fs-@size">@size</label>
                </div>
            }
        </div>
    </div>

    @* Language *@
    <div class="mb-4">
        <h5>Language</h5>
        <select class="form-select" style="max-width: 300px" @bind="Language">
            <option value="English">English</option>
            <option value="Spanish">Spanish</option>
            <option value="French">French</option>
            <option value="German">German</option>
            <option value="Japanese">Japanese</option>
            <option value="Chinese">Chinese</option>
        </select>
    </div>

    @* Compact Mode *@
    <div class="mb-4">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="compactMode"
                   checked="@CompactMode"
                   @onchange="e => CompactMode = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="compactMode">Compact Mode</label>
        </div>
        <small class="text-muted">Reduce spacing and padding throughout the interface</small>
    </div>

    @* Live Preview *@
    <div class="mb-4">
        <h5>Preview</h5>
        <div class="appearance-preview @PreviewThemeClass" style="font-size: @PreviewFontSize;">
            <div class="preview-header">
                <strong>Sample Dashboard</strong>
                <span class="preview-badge">@Language</span>
            </div>
            <div class="preview-body @(CompactMode ? "compact" : "")">
                <p class="preview-text">This is how your content will look with the selected settings.</p>
                <div class="preview-card">
                    <span>📊 Analytics</span>
                    <span class="preview-value">1,234</span>
                </div>
                <div class="preview-card">
                    <span>👥 Users</span>
                    <span class="preview-value">567</span>
                </div>
            </div>
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @(_saving ? "Saving..." : "Save")
    </button>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 fade-in" role="alert">
            ✅ Appearance settings saved!
        </div>
    }
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;
    private bool _saving;
    private bool _showSuccess;

    private string PreviewThemeClass => Theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontSize => FontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_saving)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@page "/settings"
@using sv_1d50f10f7991409b88dacb4ce670e5ee.Models
@using sv_1d50f10f7991409b88dacb4ce670e5ee.Services
@using sv_1d50f10f7991409b88dacb4ce670e5ee.Components.Pages.Settings
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => { _activeSection = s; }" />

    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_profile" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@_notificationPrefs" OnSave="SaveNotificationPrefsAsync" />
                    break;
                case "Security":
                    <SecuritySection Security="@_security"
                                     OnRevokeSession="RevokeSessionAsync"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnToggleTwoFactor="ToggleTwoFactorAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@_appearance" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllAsync();
        _loading = false;
    }

    private async Task LoadAllAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notificationPrefs = notifsTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task ToggleTwoFactorAsync(bool enabled)
    {
        if (_security is not null)
        {
            _security = _security with { TwoFactorEnabled = enabled };
        }
        await Task.CompletedTask;
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

