+                    <span class="visually-hidden">Loading...</span>
+                </div>
+            </div>
+        }
+        else
+        {
+            @switch (_activeSection)
+            {
+                case "Profile":
+                    <ProfileSection Profile="@_profile" OnSave="SaveProfileAsync" />
+                    break;
+                case "Notifications":
+                    <NotificationsSection Prefs="@_notificationPrefs" OnSave="SaveNotificationPrefsAsync" />
+                    break;
+                case "Security":
+                    <SecuritySection Security="@_security"
+                                     OnRevokeSession="RevokeSessionAsync"
+                                     OnChangePassword="ChangePasswordAsync"
+                                     OnToggleTwoFactor="ToggleTwoFactorAsync" />
+                    break;
+                case "Appearance":
+                    <AppearanceSection Settings="@_appearance" OnSave="SaveAppearanceAsync" />
+                    break;
+            }
+        }
+    </div>
+</div>
+
+@code {
+    private string _activeSection = "Profile";
+    private bool _loading = true;
+
+    private UserProfile? _profile;
+    private NotificationPrefs? _notificationPrefs;
+    private SecuritySettings? _security;
+    private AppearanceSettings? _appearance;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadAllAsync();
+        _loading = false;
+    }
+
+    private async Task LoadAllAsync()
+    {
+        var profileTask = SettingsService.GetProfileAsync();
+        var notifsTask = SettingsService.GetNotificationPrefsAsync();
+        var securityTask = SettingsService.GetSecuritySettingsAsync();
+        var appearanceTask = SettingsService.GetAppearanceAsync();
+
+        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);
+
+        _profile = profileTask.Result;
+        _notificationPrefs = notifsTask.Result;
+        _security = securityTask.Result;
+        _appearance = appearanceTask.Result;
+    }
+
+    private async Task SaveProfileAsync(UserProfile profile)
+    {
+        await SettingsService.SaveProfileAsync(profile);
+        _profile = profile;
+    }
+
+    private async Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
+    {
+        await SettingsService.SaveNotificationPrefsAsync(prefs);
+        _notificationPrefs = prefs;
+    }
+
+    private async Task ChangePasswordAsync((string Current, string New) args)
+    {
+        await SettingsService.ChangePasswordAsync(args.Current, args.New);
+        _security = await SettingsService.GetSecuritySettingsAsync();
+    }
+
+    private async Task RevokeSessionAsync(string sessionId)
+    {
+        await SettingsService.RevokeSessionAsync(sessionId);
+        _security = await SettingsService.GetSecuritySettingsAsync();
+    }
+
+    private async Task ToggleTwoFactorAsync(bool enabled)
+    {
+        if (_security is not null)
+        {
+            _security = _security with { TwoFactorEnabled = enabled };
+        }
+        await Task.CompletedTask;
+    }
+
+    private async Task SaveAppearanceAsync(AppearanceSettings settings)
+    {
+        await SettingsService.SaveAppearanceAsync(settings);
+        _appearance = settings;
+    }
+}
+

toolArgs.file_text:
/* ─── Settings Layout ─── */
.settings-layout {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
}

/* ─── Sidebar ─── */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    font-weight: 600;
    color: #495057;
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
    cursor: pointer;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 500;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* ─── Content Area ─── */
.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    max-width: 800px;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
    font-weight: 600;
}

.settings-section .text-muted {
    margin-bottom: 1.5rem;
}

/* ─── Profile ─── */
.profile-avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-preview {
    flex-shrink: 0;
}

.avatar-img {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.avatar-placeholder {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.85rem;
}

.avatar-url-display {
    flex: 1;
    padding-top: 0.25rem;
}

/* ─── Appearance Preview ─── */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.2s;
}

.preview-header {
    padding: 0.75rem 1rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid #dee2e6;
}

.preview-badge {
    font-size: 0.75rem;
    padding: 0.2rem 0.5rem;
    border-radius: 4px;
    background: #e9ecef;
    color: #495057;
}

.preview-body {
    padding: 1rem;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.preview-body.compact {
    padding: 0.5rem 1rem;
    gap: 0.35rem;
}

.preview-text {
    margin: 0;
    color: inherit;
}

.preview-card {
    display: flex;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    background: rgba(0,0,0,0.03);
}

.preview-value {
    font-weight: 600;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #45475a;
}

.preview-dark .preview-badge {
    background: #45475a;
    color: #cdd6f4;
}

.preview-dark .preview-card {
    background: rgba(255,255,255,0.05);
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: #f0f0f0;
}

/* ─── Animations ─── */
.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

